&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rarr; (45 - 15) &amp;times; 4&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr; 30&amp;nbsp;&amp;times; 4 = 120.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;For, (27, 8, 76)&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rarr; (27&amp;nbsp;- 8)&amp;nbsp;&amp;times; 4&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr; 19&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;times; 4 = 76.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;Similarly, for&amp;nbsp;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;(56, 48, 32)&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;rarr; (56&amp;nbsp;- 48)&amp;nbsp;&amp;times; 4&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr; 8&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;times; 4 = 32&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;Hence, the correct answer is&lt;strong&gt; &amp;quot;Option 4&amp;quot;.&lt;/strong&gt;&lt;/p&gt;

